async function main() {
  for (const item of updates) {
    const descWords = item.description.split(/\s+/).length;
    const metaLen = item.metaDescription.length;
    console.log(`Updating: ${item.slug} | desc: ${descWords} words | meta: ${metaLen} chars`);
    if (descWords < 250) {
      console.warn(`  ⚠️ DESCRIPTION TOO SHORT: ${descWords} words (need 250+)`);
    }
    if (metaLen < 130 || metaLen > 155) {
      console.warn(`  ⚠️ META OUT OF RANGE: ${metaLen} chars (need 130-155)`);
    }
    await prisma.product.update({
      where: { slug: item.slug },
      data: {
        description: item.description,
        metaDescription: item.metaDescription
      }
    });
    console.log(`  ✓ Updated successfully`);
  }
  console.log(`\nDone — ${updates.length} products updated`);
}

main().then(() => prisma.$disconnect()).catch(e => { console.error(e); prisma.$disconnect(); });
